import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';

const DetalheCliente = () => {
  const { id } = useParams();
  const [cliente, setCliente] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch(`http://localhost:5000/api/clientes/${id}`)
      .then(resp => resp.json())
      .then(data => {
        setCliente(data);
        setLoading(false);
      });
  }, [id]);

  if (loading) return <p>Carregando detalhes...</p>;
  if (!cliente || cliente.error) return <p>Cliente não encontrado.</p>;

  return (
    <div style={{maxWidth:'700px',margin:'2rem auto',background:'#f8fafc',padding:'2rem',borderRadius:'8px'}}>
      <Link to="/" style={{textDecoration:'none',color:'#1976d2'}}>&larr; Voltar</Link>
      <h2 style={{color:'#153a6b',marginTop:'1rem'}}>Detalhes do Cliente</h2>
      <p><strong>Razão Social:</strong> {cliente.razaoSocial}</p>
      <p><strong>CNPJ:</strong> {cliente.cnpj}</p>
      <p><strong>Email:</strong> {cliente.email}</p>
      <p><strong>Telefone:</strong> {cliente.telefone}</p>
      <p><strong>Consultoria:</strong> {cliente.consultoria}</p>
      <p><strong>Status:</strong> {cliente.status}</p>
      {/* Aqui você pode adicionar abas para serviços, comprovantes, etc. */}
    </div>
  );
};

export default DetalheCliente;
